import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';

function Register() {
  const navigate = useNavigate();
  const [role, setRole] = useState(null);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    password: '',
    confirmPassword: ''
  });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleRegister = async (e) => {
    e.preventDefault();
    if (formData.password !== formData.confirmPassword) {
      setError('Passwords do not match');
      return;
    }
    setLoading(true);
    setError('');
    try {
      const response = await fetch('http://localhost:8080/auth/register', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          fullName: formData.name,
          email: formData.email,
          password: formData.password,
          role: role
        })
      });
      const data = await response.json();
      if (data.success) {
        navigate('/login');
      } else {
        setError(data.error || 'Registration failed');
      }
    } catch (err) {
      setError('Connection error. Is the backend running?');
    } finally {
      setLoading(false);
    }
  };

  if (!role) {
    return (
      <div className="page-wrapper">
        <div className="auth-card">
          <div className="auth-header">
            <div className="brand-logo">✨</div>
            <h1>GlamSched</h1>
            <p className="subtitle">Join the Beauty Community</p>
          </div>
          <div className="auth-body">
            <h2>I am a…</h2>
            <div className="role-cards">
              <div className="role-card" onClick={() => setRole('CLIENT')}>
                <span className="role-icon">💅</span>
                <h3>Client</h3>
                <p>Discover &amp; book beauty services</p>
              </div>
              <div className="role-card" onClick={() => setRole('ARTIST')}>
                <span className="role-icon">🎨</span>
                <h3>Artist</h3>
                <p>Showcase &amp; manage your services</p>
              </div>
            </div>
            <div className="auth-footer">
              Already have an account? <Link to="/login">Sign in</Link>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="page-wrapper">
      <div className="auth-card">
        <div className="auth-header">
          <div className="brand-logo">{role === 'CLIENT' ? '💅' : '🎨'}</div>
          <h1>GlamSched</h1>
          <p className="subtitle">Create your account</p>
        </div>
        <div className="auth-body">
          <div className="role-badge">{role === 'CLIENT' ? '💅 Client' : '🎨 Artist'}</div>
          <form onSubmit={handleRegister}>
            <div className="input-group">
              <span className="input-icon">👤</span>
              <input
                name="name"
                placeholder="Full Name"
                value={formData.name}
                onChange={handleChange}
                required
              />
            </div>
            <div className="input-group">
              <span className="input-icon">✉️</span>
              <input
                name="email"
                type="email"
                placeholder="Email address"
                value={formData.email}
                onChange={handleChange}
                required
              />
            </div>
            <div className="input-group">
              <span className="input-icon">🔒</span>
              <input
                name="password"
                type="password"
                placeholder="Password"
                value={formData.password}
                onChange={handleChange}
                required
              />
            </div>
            <div className="input-group">
              <span className="input-icon">🔒</span>
              <input
                name="confirmPassword"
                type="password"
                placeholder="Confirm Password"
                value={formData.confirmPassword}
                onChange={handleChange}
                required
              />
            </div>
            {error && <div className="error-msg">{error}</div>}
            <button className="btn-primary" type="submit" disabled={loading}>
              {loading ? 'Creating account…' : 'Create Account'}
            </button>
          </form>
          <button className="btn-secondary" onClick={() => setRole(null)}>← Change Role</button>
        </div>
      </div>
    </div>
  );
}

export default Register;
